            // Visitor skips subscript elements entirely
            var _visitor_visitor_subscript_skip = new VisitorSubscriptSkipVisitor();
            var options = new ConversionOptions { Visitor = _visitor_visitor_subscript_skip };
            var result = HtmlToMarkdownRs.Convert("<p>The formula C<sub>12</sub>H<sub>22</sub>O<sub>11</sub> is sugar.</p>", options);
    Assert.Contains("the formula cho is sugar.", result.Content.ToString().ToLower());

        }

        [Fact]
        public void Test_VisitorSuperscriptCustom()
        {
            // Visitor replaces superscript with custom template
            var _visitor_visitor_superscript_custom = new VisitorSuperscriptCustomVisitor();
            var options = new ConversionOptions { Visitor = _visitor_visitor_superscript_custom };
            var result = HtmlToMarkdownRs.Convert("<p>Einstein's E=mc<sup>2</sup> revolutionized physics.</p>", options);
    Assert.Contains("e=mc^2^", result.Content.ToString().ToLower());
    Assert.Contains("revolutionized physics", result.Content.ToString().ToLower());

        }

        [Fact]
        public void Test_VisitorSuperscriptSkip()
        {
            // Visitor skips superscript from output
            var _visitor_visitor_superscript_skip = new VisitorSuperscriptSkipVisitor();
            var options = new ConversionOptions { Visitor = _visitor_visitor_superscript_skip };
