        }

        [Fact]
        public void Test_VisitorUnderlineCustom()
        {
            // Visitor replaces underline with custom markup
            var _visitor_visitor_underline_custom = new VisitorUnderlineCustomVisitor();
            var options = new ConversionOptions { Visitor = _visitor_visitor_underline_custom };
            var result = HtmlToMarkdownRs.Convert("<p>This is <u>very important</u> text.</p>", options);
    Assert.Contains("_very important_", result.Content.ToString().ToLower());
    Assert.DoesNotContain("**", result.Content.ToString());

        }

        [Fact]
        public void Test_VisitorUnderlineSkip()
        {
            // Visitor skips underline elements from output
            var _visitor_visitor_underline_skip = new VisitorUnderlineSkipVisitor();
            var options = new ConversionOptions { Visitor = _visitor_visitor_underline_skip };
            var result = HtmlToMarkdownRs.Convert("<p>Normal text with <u>underlined part</u> and more text.</p>", options);
    Assert.Contains("normal text with", result.Content.ToString().ToLower());
    Assert.Contains("and more text.", result.Content.ToString().ToLower());
    Assert.DoesNotContain("underlined part", result.Content.ToString());

        }

        [Fact]
        public void Test_VisitorVideoCustom()
        {
            // Visitor replaces video with custom link
            var _visitor_visitor_video_custom = new VisitorVideoCustomVisitor();
            var options = new ConversionOptions { Visitor = _visitor_visitor_video_custom };
            var result = HtmlToMarkdownRs.Convert("<p>Watch our tutorial:</p><video src=\"tutorial.mp4\" width=\"320\" height=\"240\" controls></video><p>Great content!</p>", options);
    Assert.Contains("[video: tutorial.mp4]", result.Content.ToString().ToLower());
    Assert.Contains("watch our tutorial:", result.Content.ToString().ToLower());
    Assert.Contains("great content!", result.Content.ToString().ToLower());

        }

        [Fact]
        public void Test_VisitorVideoSkip()
        {
            // Visitor removes video elements entirely
            var _visitor_visitor_video_skip = new VisitorVideoSkipVisitor();
            var options = new ConversionOptions { Visitor = _visitor_visitor_video_skip };
            var result = HtmlToMarkdownRs.Convert("<h2>Demo</h2><video src=\"demo.webm\"></video><p>See the demo above.</p>", options);
    Assert.Contains("demo", result.Content.ToString().ToLower());
    Assert.Contains("see the demo above.", result.Content.ToString().ToLower());
    Assert.DoesNotContain("demo.webm", result.Content.ToString());

        }


